  'foshan/wingchun': ('Wing Chun', 'Sebagai tempat lahirnya seni bela diri Wing Chun, kota ini menjadi akar sejarah bagi Ip Man dan Bruce Lee.'),
  'foshan/lion': ('Barongsai', 'Dikenal sebagai ibu kota barongsai selatan, pertunjukan singa yang penuh warna ini sering melompat lincah di atas tiang-tiang tinggi.'),
  'foshan/ceramic': ('Keramik Shiwan', 'Tungku pembakaran berusia seribu tahun masih terus memproduksi figurin keramik Shiwan yang ekspresif.'),
  'foshan/opera': ('Opera Kanton', 'Seni panggung yang paling digemari di Tiongkok selatan ini berkembang pesat di tanah ini.'),
  'guiyang/pavilion': ('Paviliun Jiaxiu', 'Paviliun tiga tingkat yang terletak di Sungai Nanming ini telah menjadi ikon kota selama 400 tahun.'),
  'guiyang/sourfish': ('Sup Ikan Asam', 'Ikan yang dimasak dalam kaldu tomat fermentasi yang segar dan asam merupakan hidangan khas dari Guizhou.'),
  'guiyang/waterfall': ('Air Terjun Huangguoshu', 'Salah satu air terjun terbesar di Asia ini mengalir deras dan sering kali memunculkan pelangi di sekitarnya.'),
  'guiyang/miao': ('Budaya Miao', 'Festival dan seni sulaman masyarakat Miao yang mengenakan mahkota perak menghiasi desa-desa di pegunungan.'),
  'changchun/film': ('Kota Film', 'Studio tempat lahirnya perfilman Tiongkok berdiri di sini, menjadikannya sebagai \'Hollywood dari Timur\'.'),
  'changchun/car': ('Kota Otomotif', 'Mobil rakitan pertama Tiongkok lahir dari pabrik-pabrik di kota ini, yang menjadikannya ibu kota otomotif nasional.'),
  'changchun/palace': ('Istana Boneka', 'Istana tempat kaisar terakhir Tiongkok pernah tinggal ini menjadi saksi bisu sejarah yang penuh gejolak.'),
  'changchun/snow': ('Salju Musim Dingin', 'Selama musim dingin yang panjang, kota ini berkilau dengan pahatan es dan arena ski.'),
  'xining/lake': ('Danau Qinghai', 'Danau air asin terbesar di Tiongkok ini terkenal dengan hamparan bunga rapeseed kuning yang mengelilinginya saat musim panas.'),
  'xining/monastery': ('Biara Kumbum', 'Salah satu dari enam biara besar Buddhisme Tibet ini tersohor karena seni pahatan mentega yak-nya.'),
  'xining/flower': ('Bunga Rapeseed', 'Pada bulan Juli, dataran tinggi ini diselimuti hamparan bunga rapeseed keemasan hingga ke cakrawala.'),
  'xining/lamb': ('Daging Yak dan Domba', 'Mi tarik dan sate domba khas kuliner Hui dan Tibet merupakan cita rasa utama di dataran tinggi ini.'),
  'guilin/karst': ('Karst Sungai Li', 'Puncak-puncak batu kapur yang menyembul dari kabut merupakan pemandangan yang tertera pada uang kertas 20 yuan.'),
  'guilin/elephant': ('Bukit Belalai Gajah', 'Batu berbentuk gajah yang sedang mencelupkan belalainya ke sungai ini merupakan lambang kebanggaan kota Guilin.'),
  'guilin/terrace': ('Terasering Sawah Longji', 'Terasering \'Punggung Naga\' yang melilit lereng gunung ini merupakan tangga warisan kerja keras selama berabad-abad.'),
  'guilin/osmanthus': ('Bunga Osmanthus', 'Nama kota ini berarti \'hutan osmanthus\', dan saat musim gugur, kota ini dipenuhi aroma manis bunga tersebut.'),
  'wenzhou/merchant': ('Semangat Pedagang', 'Sering dijuluki sebagai \'Yahudi Tiongkok\', para pengusaha Wenzhou membangun jaringan bisnis di seluruh dunia.'),
  'wenzhou/shoe': ('Sepatu dan Kulit', 'Sebagian besar pasokan sepatu kulit dunia diproduksi di kota industri ini.'),
  'wenzhou/mountain': ('Pegunungan Yandang', 'Terkenal dengan air terjun dan puncak-puncak tajamnya, pegunungan ini dijuluki sebagai \'gunung pertama di tepi laut\'.'),
  'wenzhou/seafood': ('Hidangan Laut', 'Cumi-cumi, kerang, dan ikan dari Laut Tiongkok Timur menjadi bahan utama dalam santapan lokal.'),
  'tangshan/memorial': ('Monumen Gempa Bumi', 'Taman monumen untuk mengenang gempa besar tahun 1976 ini menjadi simbol kebangkitan kota Tangshan.'),
  'tangshan/coal': ('Tambang Batu Bara dan Baja', 'Tambang batu bara dan jalur kereta api modern pertama di Tiongkok dibuka di sini sebagai pusat industri awal.'),
  'tangshan/ceramic': ('Keramik Tangshan', 'Dikenal sebagai kota porselen di utara, keramik tulang dari daerah ini menghiasi meja makan dengan keanggunan.'),
  'tangshan/lake': ('Taman Nanhu', 'Taman danau yang dibangun di atas bekas lubang tambang ini kini berfungsi sebagai paru-paru hijau kota.'),
  'anshan/steel': ('Kota Baja', 'Pabrik baja terbesar di Tiongkok didirikan di sini, menjadikannya ibu kota baja bagi negara tersebut.'),
  'anshan/jade': ('Giok Xiuyan', 'Kota ini merupakan pusat giok Tiongkok dan menjadi tempat bagi ukiran giok terbesar di dunia.'),
  'anshan/mountain': ('Gunung Qian', 'Dikenal sebagai Puncak Seribu Teratai, gunung ini merupakan puncak suci di utara yang dipenuhi kuil dan tebing curam.'),
  'anshan/spring': ('Pemandian Air Panas Tanggangzi', 'Pemandian air panas yang telah digunakan selama seribu tahun untuk penyembuhan ini dulunya sering dikunjungi oleh para kaisar.'),
  'linyi/market': ('Pasar Grosir', 'Pusat grosir terbesar di Tiongkok Utara ini mendistribusikan berbagai macam barang ke seluruh penjuru negeri.'),
  'linyi/brush': ('Master Kaligrafi', 'Linyi adalah tempat kelahiran Wang Xizhi, sang maestro kaligrafi Tiongkok yang dikenal sebagai tanah tinta.'),
  'linyi/mountain': ('Gunung Meng', 'Gunung tertinggi kedua di Shandong ini merupakan kawasan wisata alam yang kaya akan udara bersih dan air terjun.'),
  'linyi/pancake': ('Pancake Yimeng', 'Pancake jagung tipis yang dikenal sebagai jianbing ini merupakan makanan pokok tradisional masyarakat pegunungan Yimeng.'),
  'cangzhou/lion': ('Singa Besi', 'Patung singa besi raksasa berusia 1.100 tahun ini menjadi simbol kebanggaan kota Cangzhou.'),
  'cangzhou/martial': ('Seni Bela Diri', 'Dikenal sebagai rumah wushu di Tiongkok, kota ini melahirkan banyak master bela diri dan perguruan silat ternama.'),
  'cangzhou/canal': ('Kanal Besar', 'Kanal Besar Beijing-Hangzhou melintasi kota ini, di mana dermaga-dermaga kuno masih berdiri hingga saat ini.'),
  'cangzhou/jujube': ('Kurma Emas', 'Kurma \'benang emas\' yang manis dan berkulit tipis ini dijuluki sebagai raja buah kering.'),
  'nantong/textile': ('Kota Tekstil', 'Sebagai pusat tekstil rumah tangga di Tiongkok, produk kain katun dari kota ini telah dipasarkan ke seluruh dunia.'),
  'nantong/mountain': ('Gunung Lang', 'Terletak di muara Sungai Yangtze, bukit suci dengan lima puncak ini menjadi destinasi ziarah sekaligus tempat untuk menikmati pemandangan.'),
  'nantong/kite': ('Layang-layang Bersiul', 'Layang-layang banyao yang dilengkapi peluit sehingga menghasilkan suara dengungan merupakan kerajinan tradisional khas kota ini.'),
  'nantong/school': ('Pelopor Pendidikan', 'Industrialis Zhang Jian mendirikan sekolah modern dan museum pertama di Tiongkok di kota ini.'),
  'taizhou/opera': ('Mei Lanfang', 'Kota ini merupakan kampung halaman dari Mei Lanfang, maestro legendaris opera Peking.'),
  'taizhou/tea': ('Teh Pagi', 'Tradisi sarapan zaocha yang terdiri dari bakpao kukus dan teh seduh telah menjadi ritual masyarakat setempat.'),
  'taizhou/boat': ('Festival Perahu Qintong', 'Pada musim semi, festival yang melibatkan ratusan pendayung perahu ini membuat suasana sungai menjadi sangat meriah.'),
  'taizhou/meatball': ('Bakso Kepala Singa', 'Bakso babi berukuran besar yang lembut ini merupakan hidangan klasik dari kuliner Huaiyang.'),
  'jinhua/ham': ('Ham Jinhua', 'Dibuat dengan metode pengawetan selama berabad-abad, ham berwarna merah ini merupakan yang paling terkenal di Tiongkok.'),
  'jinhua/film': ('Studio Hengdian', 'Sebagai lokasi syuting luar ruangan terbesar di dunia, tempat ini menjadi latar bagi banyak drama sejarah Tiongkok.'),
  'jinhua/cave': ('Gua Shuanglong', 'Gua bawah tanah yang dimasuki dengan perahu melalui celah batu rendah ini menawarkan pemandangan yang memukau.'),
  'jinhua/bridge': ('Jembatan Kuno', 'Jembatan batu melengkung dan kota air di sini memancarkan keanggunan khas wilayah Jiangnan.'),
  'wuhu/park': ('Fangte Wonderland', 'Salah satu taman hiburan terbesar di Tiongkok ini menawarkan pengalaman liburan yang penuh keseruan bagi keluarga.'),
  'wuhu/ironart': ('Lukisan Besi', 'Lukisan besi yang elegan dan ditempa dari besi tempa merupakan kerajinan tangan yang telah berusia 300 tahun.'),
  'wuhu/rice': ('Pelabuhan Beras', 'Kota yang terletak di tepi Sungai Yangtze ini secara historis merupakan pasar beras terbesar di Tiongkok.'),
  'wuhu/river': ('Pelabuhan Yangtze', 'Pelabuhan sungai yang sibuk ini menjadikan kota tersebut sebagai gerbang laut bagi Provinsi Anhui.'),
  'huangshan/peak': ('Gunung Huangshan', 'Dengan puncak granit, lautan awan, dan pohon pinus yang unik, gunung ini merupakan gunung paling terkenal di Tiongkok.'),
  'huangshan/village': ('Desa Hongcun', 'Desa bergaya Hui yang dikelilingi air dengan dinding putih ini terdaftar sebagai Situs Warisan Dunia UNESCO dan tampak seperti lukisan hidup.'),
  'huangshan/tea': ('Teh Maofeng', 'Teh hijau berujung halus yang dipetik di lereng berkabut ini merupakan salah satu dari sepuluh teh paling terkenal di Tiongkok.'),
  'huangshan/ink': ('Tinta dan Seni Huizhou', 'Tinta Hui, rumah kayu berukir, dan kaligrafi merupakan harta karun budaya di wilayah ini.'),
  'yichun/moon': ('Gunung Mingyue', 'Gunung \'Bulan Terang\' ini terkenal dengan pemandian air panas dan pemandangan dari kereta gantungnya.'),
  'yichun/spring': ('Pemandian Air Panas', 'Mata air panas kaya selenium yang langka menjadikan kota ini pusat pemandian spa di Tiongkok.'),
  'yichun/zen': ('Buddhisme Chan', 'Kuil-kuil di pegunungan yang berakar pada sekte Chan Tiongkok mengajak pengunjung untuk menemukan ketenangan.'),
  'yichun/rice': ('Dataran Padi', 'Dataran subur Yuan-He telah lama menjadi lumbung padi bagi Provinsi Jiangxi.'),
  'zhangzhou/narcissus': ('Bunga Bakung', 'Bunga bakung paling terkenal di Tiongkok tumbuh di sini dan menjadi lambang perayaan musim semi.'),
  'zhangzhou/tulou': ('Tulou Hakka', 'Benteng tanah berbentuk bulat raksasa ini terdaftar sebagai Situs Warisan Dunia UNESCO dan mampu menampung satu desa di bawah satu atap.'),
  'zhangzhou/banana': ('Buah Tropis', 'Kebun pisang, lengkeng, dan jeruk keprok menjaga delta yang hangat ini tetap hijau sepanjang tahun.'),
  'zhangzhou/coast': ('Pulau Dongshan', 'Dengan pantai keemasan dan desa nelayan, pulau ini merupakan permata di pesisir selatan.'),
  'guangzhou/tower': ('Canton Tower', 'Menara ramping yang dijuluki \'Pinggang Kecil\' ini merupakan salah satu menara tertinggi di dunia yang menghiasi kota dengan warna-warni lampu malam.'),
  'guangzhou/dimsum': ('Yum Cha', 'Yum cha, yaitu dim sum yang dikukus dalam keranjang bambu ditemani teh seduh, adalah jiwa dari tradisi kuliner Kanton.'),
  'guangzhou/academy': ('Akademi Klan Chen', 'Terkenal dengan ukiran kayu dan hiasan keramiknya, aula klan ini merupakan mahakarya kerajinan khas Kanton.'),
  'guangzhou/flower': ('Kota Bunga', 'Karena bunganya mekar sepanjang tahun, Guangzhou mengadakan pameran bunga besar-besaran setiap tahun baru dan dijuluki sebagai \'Kota Bunga\'.'),
  'wuhan/crane': ('Menara Bangau Kuning', 'Menghadap ke Sungai Yangtze, menara berusia ribuan tahun ini telah menginspirasi banyak puisi Tiongkok yang paling terkenal.'),
  'wuhan/noodle': ('Mi Kering Pedas', 'Mi kering dengan saus wijen merupakan menu sarapan yang wajib dicoba di Wuhan.'),
  'wuhan/duckneck': ('Leher Bebek Pedas', 'Leher bebek rebus yang pedas adalah camilan favorit warga kota untuk menemani obrolan larut malam.'),
  'wuhan/university': ('Bunga Sakura Kampus', 'Bunga sakura di Universitas Wuhan menarik ribuan pengunjung setiap musim semi.'),
  'tianjin/eye': ('Tianjin Eye', 'Kincir ria yang dibangun di atas jembatan ini menyuguhkan pemandangan kedua sisi sungai sekaligus.'),
  'tianjin/baozi': ('Bakpao Goubuli', 'Bakpao kukus isi daging babi dengan lipatan khas ini telah menjadi kuliner ikonik kota selama 150 tahun.'),
  'tianjin/crosstalk': ('Komedi Crosstalk', 'Komedi tutur dua orang yang disebut \'xiangsheng\' adalah tradisi Tianjin yang lahir di kedai-kedai teh.'),
  'tianjin/architecture': ('Kawasan Eropa', 'Vila-vila bergaya Eropa di Lima Jalan Utama membuat kota ini dijuluki sebagai \'museum arsitektur\'.'),
  'xiamen/island': ('Pulau Gulangyu', 'Jalanan bebas kendaraan dan vila-vila kolonial menjadikan pulau yang terdaftar di UNESCO ini sebagai museum terbuka.'),
  'xiamen/piano': ('Pulau Piano', 'Dengan jumlah piano per kapita terbanyak, Gulangyu dikenal sebagai \'pulau piano\'.'),
  'xiamen/egret': ('Bangau Putih', 'Bangau putih yang menjadi lambang kota ini mengingatkan pada nama lama Xiamen, yaitu \'pulau bangau\'.'),
  'xiamen/oyster': ('Omelet Tiram', 'Omelet renyah yang terbuat dari tiram segar dan telur merupakan hidangan andalan di kawasan pesisir ini.'),
  'harbin/ice': ('Festival Es', 'Festival musim dingin yang menampilkan istana-istana es raksasa berlampu ini adalah yang terbesar di dunia.'),
  'harbin/cathedral': ('Katedral Santa Sophia', 'Katedral Ortodoks Rusia dengan kubah bawang ini merupakan lambang sejarah Eropa di kota Harbin.'),
  'harbin/sausage': ('Sosis Merah', 'Sosis merah asap bergaya Rusia ini merupakan kuliner khas kota yang telah ada selama seabad.'),
  'harbin/accordion': ('Kota Musik', 'Kental dengan warisan budaya Rusia, Harbin menjadi tempat berdirinya orkestra simfoni pertama di Tiongkok.'),
  'fuzhou/alley': ('Tiga Jalur dan Tujuh Gang', 'Kawasan kota tua dengan dinding putih dan atap hitam ini merupakan museum hidup arsitektur era Ming dan Qing.'),
  'fuzhou/banyan': ('Kota Beringin', 'Pohon beringin raksasa yang berusia ratusan tahun menaungi jalanan kota, menjuluki Fuzhou sebagai \'Kota Beringin\'.'),
  'fuzhou/hotspring': ('Pemandian Air Panas', 'Sumber air panas yang muncul di pusat kota telah mengaliri pemandian umum selama seribu tahun.'),
  'fuzhou/soup': ('Buddha Jumps Over the Wall', 'Sup mewah yang dimasak dari puluhan bahan pilihan ini merupakan mahakarya kuliner khas Fujian.'),
  'dongguan/robot': ('Pabrik Dunia', 'Dengan pabrik-pabrik yang terotomatisasi, Dongguan memproduksi sebagian besar kebutuhan elektronik dunia.'),
  'dongguan/basketball': ('Kota Bola Basket', 'Klub bola basket paling berprestasi di Tiongkok bermarkas di kota yang dijuluki sebagai \'Kota Bola Basket\' ini.'),
  'dongguan/keyuan': ('Taman Keyuan', 'Salah satu dari empat taman klasik paling terkenal di Guangdong yang dikagumi karena kolam dan paviliunnya.'),
  'dongguan/cannon': ('Benteng Humen', 'Benteng Humen, tempat dimulainya Perang Candu, menandai pesisir tempat candu pernah dimusnahkan.'),
  'lanzhou/beefnoodle': ('Mi Sapi Lanzhou', 'Dengan kaldu sapi bening dan mi tarik tangan, Lanzhou dikenal sebagai ibu kota mi di Tiongkok.'),
  'lanzhou/waterwheel': ('Kincir Air', 'Kincir air raksasa di tepi Sungai Kuning melambangkan teknik irigasi yang telah digunakan selama berabad-abad.'),
  'lanzhou/statue': ('Patung Ibu Sungai Kuning', 'Patung ibu dan anak di tepi sungai ini melambangkan sungai yang telah menghidupi peradaban Tiongkok.'),
  'lanzhou/raft': ('Rakit Kulit Domba', 'Rakit tradisional yang terbuat dari kulit domba yang ditiup hingga kini masih mengapung di Sungai Kuning.'),
  'urumqi/bazaar': ('Grand Bazaar', 'Dengan menara masjid dan kedai rempah-rempah, pasar ini menghadirkan nuansa Jalur Sutra yang kental.'),
  'urumqi/tianshan': ('Danau Surgawi', 'Terletak di bawah puncak bersalju Pegunungan Tianshan, Danau Surgawi dikelilingi oleh hutan pohon cemara yang asri.'),
  'urumqi/kebab': ('Kebab Domba', 'Sate domba berbumbu yang dipanggang di atas bara api merupakan hidangan wajib dalam jamuan masyarakat Uighur.'),
  'urumqi/dance': ('Tarian Uighur', 'Tarian Uighur yang berputar dengan iringan musik drum dan rawap selalu memeriahkan setiap perayaan.'),
  'haikou/coconut': ('Kota Kelapa', 'Jalanan yang dipenuhi pohon kelapa memberikan julukan \'Kota Kelapa\' bagi Haikou.'),
  'haikou/arcade': ('Arcade Qilou', 'Bangunan bergaya \'qilou\' dengan pilar-pilar khas di bagian selatan membentuk jalanan arcade yang teduh.'),
  'haikou/crater': ('Kawah Vulkanik', 'Kawah gunung berapi yang sudah tidak aktif kini membentuk taman geopark hijau di pinggiran kota.'),
  'haikou/turtle': ('Laut Tropis', 'Perairan yang hangat dan jernih dengan terumbu karang menjadikan pesisir ini habitat bagi penyu laut.'),
  'luoyang/grotto': ('Gua Longmen', 'Puluhan ribu patung Buddha yang dipahat pada tebing batu membentuk situs warisan dunia UNESCO yang menakjubkan.'),
  'luoyang/peony': ('Ibu Kota Peony', 'Ribuan bunga peony yang mekar setiap bulan April menjadikan Luoyang dijuluki sebagai ibu kota bunga peony.'),
  'luoyang/whitehorse': ('Kuil Kuda Putih', 'Didirikan pada tahun 68 Masehi, kuil ini dianggap sebagai biara Buddha pertama di Tiongkok.'),
  'luoyang/capital': ('Ibu Kota Kuno', 'Sebagai ibu kota dari tiga belas dinasti, Luoyang merupakan salah satu pusat peradaban Tiongkok.'),
  'shantou/gongfutea': ('Teh Gongfu', 'Diseduh secara khidmat dalam cangkir-cangkir kecil, teh gongfu khas Chaoshan merupakan seni keramah-tamahan yang tinggi.'),
  'shantou/beefpot': ('Hotpot Daging Sapi', 'Hotpot khas Chaoshan yang menyajikan irisan daging sapi segar yang dimasak dalam hitungan detik sangatlah populer.'),
  'shantou/opera': ('Opera Teochew', 'Opera Teochew yang telah berusia 600 tahun dikenal karena nyanyiannya yang lembut dan kostumnya yang bersulam indah.'),
  'shantou/harbor': ('Pelabuhan Shantou', 'Sebagai kampung halaman banyak perantau Tionghoa, pelabuhan ini merupakan gerbang perdagangan maritim yang bersejarah.'),
  'baoding/mansion': ('Kediaman Gubernur', 'Kantor pemerintahan provinsi tertinggi dari era Dinasti Qing ini merupakan aula pemerintahan yang terpelihara dengan baik.'),
  'baoding/donkeyburger': ('Burger Keledai', 'Daging keledai berbumbu yang disajikan di dalam roti pipih renyah merupakan jajanan khas daerah ini.'),
  'baoding/balls': ('Bola Kesehatan', 'Tradisi menggerakkan bola logam di telapak tangan untuk kesehatan ini telah dilakukan selama berabad-abad.'),
  'baoding/reeds': ('Rawa Baiyangdian', 'Lahan basah terbesar di wilayah utara ini merupakan surga bagi burung dengan pemandangan alang-alang dan bunga teratai.'),
  'jilin/rime': ('Bunga Es', 'Lapisan es putih yang menyelimuti pepohonan di tepi Sungai Songhua merupakan salah satu dari empat keajaiban alam Tiongkok.'),
  'jilin/snowboard': ('Resor Ski', 'Dengan tumpukan salju yang tebal dan musim dingin yang panjang, kota ini menjadi salah satu destinasi ski terbaik di wilayah utara.'),
  'jilin/meteorite': ('Museum Meteorit', 'Museum ini memamerkan meteorit batu terbesar di dunia yang jatuh pada tahun 1976.'),
  'jilin/skate': ('Sungai Songhua yang Membeku', 'Saat musim dingin, Sungai Songhua yang membeku berubah menjadi arena es yang dipenuhi oleh pemain seluncur dan pejalan kaki.'),
  'ordos/khan': ('Mausoleum Genghis Khan', 'Mausoleum megah yang menghormati pahlawan padang rumput Genghis Khan ini merupakan pusat kebudayaan Mongol.'),
  'ordos/cashmere': ('Kasmir', 'Kain kasmir yang ditenun dari wol kambing Erdos telah membawa kota ini ke kancah industri tekstil dunia.'),
  'ordos/sanddune': ('Bukit Pasir Bernyanyi', 'Bukit pasir raksasa yang mengeluarkan suara saat disusuri ini merupakan destinasi wisata favorit di Gurun Kubuqi.'),
  'ordos/yurt': ('Yurt Mongolia', 'Tenda kain putih yang didirikan di padang rumput luas ini melambangkan kehidupan nomaden masyarakat setempat.'),
  'jining/confucius': ('Kuil Konfusius', 'Terletak di Qufu, kompleks kuil, kediaman, dan makam filsuf Konfusius ini telah terdaftar sebagai Situs Warisan Dunia UNESCO.'),
  'jining/barge': ('Kanal Besar', 'Sebagai pelabuhan sibuk di jalur Kanal Beijing-Hangzhou, Jining dulunya merupakan pusat kebudayaan kanal yang penting.'),
  'jining/sword': ('Pahlawan Liangshan', 'Sebanyak 108 pahlawan dalam kisah klasik \'Batas Air\' berkumpul di perbukitan rawa ini.'),
  'jining/fishnet': ('Danau Weishan', 'Di danau teratai terbesar di utara ini, para nelayan masih menebar jala dengan cara tradisional.'),
  'langfang/culture': ('Pusat Budaya Jalur Sutra', 'Pusat kebudayaan modern yang megah ini mengumpulkan berbagai seni dari Jalur Sutra di bawah satu atap.'),
  'langfang/furniture': ('Kota Furnitur', 'Kawasan Xianghe di dekatnya merupakan salah satu pusat pembuatan dan perdagangan furnitur terbesar di Tiongkok.'),
  'langfang/tunnel': ('Terowongan Perang Kuno', 'Terowongan militer berusia ribuan tahun yang digali di bawah tanah ini merupakan jejak pertahanan perbatasan masa lampau.'),
  'langfang/themepark': ('Taman \'Kota No. 1\'', 'Taman hiburan luas yang merekonstruksi kota bertembok kuno ini menjadi destinasi wisata keluarga yang populer.'),
  'yancheng/salt': ('Kota Garam', 'Namanya berarti \'benteng garam\', karena selama berabad-abad Yancheng menjadi pusat produksi garam di Tiongkok.'),
